/* Reasoning GP — Articles data (batch 7: C topics)
   RCGP/SCA examiner depth. NICE NG12 (May 2025) 2WW pathways stated explicitly where relevant. */
(function(){
  const A = (window.RGP_ARTICLES = window.RGP_ARTICLES || []);
  A.push(

  { id:'chronic-pancreatitis', title:'Chronic pancreatitis', category:'Gastroenterology', icon:'🔥',
    overview:'Progressive, irreversible inflammation and fibrosis of the pancreas causing chronic pain and, over time, loss of both exocrine (digestion) and endocrine (insulin) function. Alcohol is the dominant cause in the UK. Management targets pain, malabsorption and diabetes — and a vigilant watch for pancreatic cancer.',
    features:[
      'Recurrent or chronic epigastric pain radiating to the back, often relieved by sitting forward and worsened by eating/alcohol',
      'Exocrine insufficiency: steatorrhoea (pale, greasy, offensive, hard-to-flush stools), weight loss and fat-soluble vitamin deficiency',
      'Endocrine insufficiency: diabetes (type 3c) developing over time',
      'Causes: chronic alcohol (commonest), smoking, genetic/hereditary, autoimmune, obstructive, and recurrent acute pancreatitis',
      'RED FLAG: new or worsening pain with weight loss or jaundice raises the possibility of pancreatic cancer arising on a background of chronic pancreatitis',
      'Investigations: faecal elastase (low in exocrine insufficiency), HbA1c, and imaging (CT/MRCP showing calcification, ductal change, atrophy)'],
    management:[
      'Treat the cause: complete alcohol cessation and smoking cessation are the most important interventions (both drive progression)',
      'Pain management: a stepwise approach with simple analgesia, then neuropathic agents; involve a pain service and avoid escalating opioids where possible',
      'Pancreatic enzyme replacement therapy (PERT, e.g. Creon) with meals/snacks for exocrine insufficiency and steatorrhoea, with dietitian support',
      'Manage type 3c diabetes (often insulin-requiring and brittle) with specialist input',
      'Address nutrition: dietitian review, fat-soluble vitamin (A, D, E, K) and B12 monitoring/replacement, and bone health (osteoporosis risk)',
      'Refer to gastroenterology for diagnosis, complication management (pseudocyst, duct obstruction, biliary stricture) and endoscopic/surgical options',
      'Maintain vigilance for pancreatic cancer — investigate new/worsening pain with weight loss or jaundice promptly',
      'Provide alcohol support, analgesia review and structured follow-up'],
    referral:[
      'Suspected chronic pancreatitis → gastroenterology for confirmation and management',
      'New/worsening pain with weight loss, jaundice, or in a patient aged 60+ with weight loss → urgent direct-access CT for pancreatic cancer (NICE NG12)',
      'Complications (pseudocyst, biliary/duodenal obstruction, intractable pain) → specialist/surgical input',
      'Difficult diabetes or malnutrition → endocrinology/dietetics'],
    source:'NICE NG104 (Pancreatitis) / NICE NG12' },

  { id:'cirrhosis', title:'Cirrhosis', category:'Gastroenterology', icon:'🟤',
    overview:'The end stage of chronic liver injury — diffuse fibrosis and nodular regeneration that distorts liver architecture. It progresses from compensated (often silent) to decompensated disease (ascites, varices, encephalopathy, jaundice). Common causes are alcohol, MASLD/metabolic, and chronic viral hepatitis. Surveillance for hepatocellular carcinoma is essential.',
    features:[
      'Compensated cirrhosis is often asymptomatic — found via abnormal LFTs, a low platelet count, or incidental imaging',
      'Signs: spider naevi, palmar erythema, gynaecomastia, clubbing, splenomegaly, ascites, jaundice and asterixis (flap)',
      'DECOMPENSATION: ascites, variceal bleeding (haematemesis/melaena), hepatic encephalopathy (confusion, reversed sleep, flap), and jaundice',
      'Common causes: alcohol, metabolic/MASLD (non-alcoholic fatty liver), chronic hepatitis B/C, autoimmune and haemochromatosis',
      'Complications: portal hypertension and varices, spontaneous bacterial peritonitis, hepatorenal syndrome, and hepatocellular carcinoma (HCC)',
      'Assessment: liver fibrosis scores/elastography, severity scores (Child-Pugh, MELD), and an ultrasound; screen for and treat the cause'],
    management:[
      'Identify and treat the underlying cause: alcohol cessation and support, weight loss/metabolic management for MASLD, and antiviral treatment for hepatitis B/C',
      'Provide alcohol-cessation support and complete abstinence advice in alcohol-related disease',
      'Vaccinate (hepatitis A and B, influenza, pneumococcal, COVID-19) and review hepatotoxic drugs/alcohol; prescribe cautiously (altered drug handling)',
      'Arrange/coordinate HCC surveillance: 6-monthly liver ultrasound (± AFP) for at-risk cirrhotic patients',
      'Refer for variceal surveillance/endoscopy and prophylaxis (e.g. non-selective beta-blocker or band ligation) per hepatology',
      'Manage complications with specialist input: ascites (salt restriction, diuretics, drainage), encephalopathy (lactulose/rifaximin), and prompt treatment of infection',
      'Nutritional support (malnutrition is common), and consider liver-transplant referral for decompensated/advanced disease',
      'Recognise decompensation early and refer/admit; provide advance care planning where disease is advanced'],
    referral:[
      'Suspected/confirmed cirrhosis → hepatology for staging, surveillance and complication management',
      'At-risk cirrhotic patients → 6-monthly ultrasound surveillance for hepatocellular carcinoma; a suspicious liver lesion → urgent referral (NICE NG12 — consider HCC pathway)',
      'Decompensation (variceal bleed, tense ascites, encephalopathy, jaundice, suspected SBP) → emergency admission',
      'Advanced disease → consider transplant assessment / palliative care'],
    source:'NICE NG50 (Cirrhosis) / NICE NG12' },

  { id:'c-diff', title:'Clostridioides difficile (C. diff) infection', category:'Infectious diseases', icon:'🦠',
    overview:'A toxin-producing bacterial gut infection that causes antibiotic-associated diarrhoea and colitis, ranging from mild illness to life-threatening pseudomembranous colitis and toxic megacolon. It typically follows antibiotic use, which disrupts the normal gut flora. Recognition, antibiotic stewardship and infection control are central.',
    features:[
      'Watery diarrhoea (sometimes with mucus/blood), abdominal pain/cramps, fever and a raised white-cell count',
      'Recent antibiotic exposure is the key risk — especially broad-spectrum agents (the "4 Cs": clindamycin, cephalosporins, co-amoxiclav, ciprofloxacin/fluoroquinolones)',
      'Other risk factors: older age, hospitalisation/care home, proton pump inhibitors, and immunosuppression',
      'SEVERE disease: marked leucocytosis (>15), rising creatinine, fever, severe abdominal pain/distension; complications include pseudomembranous colitis, toxic megacolon and perforation',
      'Recurrence is common after an initial episode',
      'Diagnosis: stool testing (GDH screen plus toxin/PCR) in someone with unexplained diarrhoea and risk factors'],
    management:[
      'Suspect and test for C. diff in anyone with unexplained diarrhoea, particularly after recent antibiotics or healthcare contact',
      'Stop the precipitating antibiotic where possible and avoid unnecessary antibiotics and antimotility agents (e.g. loperamide)',
      'First-line treatment is oral vancomycin (per current guidance); fidaxomicin is used, especially to reduce recurrence; review PPI use',
      'Assess severity and hydration; ensure fluid/electrolyte support',
      'Infection control: isolate the patient, use gloves/aprons and soap-and-water handwashing (alcohol gel does not kill spores), and clean the environment',
      'Admit patients with severe disease or complications; surgical review for toxic megacolon/perforation',
      'Manage recurrence per specialist guidance (e.g. fidaxomicin; consider faecal microbiota transplant for multiple recurrences)',
      'Reinforce antibiotic stewardship to prevent future episodes and notify/record per local policy'],
    referral:[
      'Severe C. diff (leucocytosis >15, rising creatinine, fever, severe pain/distension) or complications (toxic megacolon, perforation) → emergency admission ± surgical assessment',
      'Dehydration, sepsis, or failure to respond → hospital assessment',
      'Multiple recurrences → specialist (consider faecal microbiota transplant)',
      'Outbreaks/healthcare-associated cases → infection-control team'],
    source:'NICE NG199 (C. difficile — antimicrobial prescribing)' },

  { id:'cluster-headache', title:'Cluster headaches', category:'Neurology', icon:'🧠',
    overview:'A trigeminal autonomic cephalalgia causing excruciating, strictly unilateral headache in bouts, with ipsilateral cranial autonomic features. Among the most severe pains known ("suicide headache"), it is frequently misdiagnosed as migraine or sinusitis. Specific acute and preventive treatments — and avoiding ineffective ones — make recognition vital.',
    features:[
      'Severe, strictly unilateral pain around or behind the eye/temple, rapid onset, lasting 15 minutes to 3 hours, often at the same time each day (especially at night)',
      'Ipsilateral autonomic features: lacrimation, conjunctival injection, nasal congestion/rhinorrhoea, eyelid oedema, ptosis/miosis, and facial sweating',
      'Restlessness/agitation during attacks (the patient paces) — unlike migraine, where they keep still',
      'Episodic pattern: clusters of frequent attacks over weeks–months, separated by remission periods; alcohol commonly triggers attacks during a cluster',
      'More common in men; differential includes migraine, trigeminal neuralgia, and secondary causes',
      'Diagnosis is clinical; neuroimaging (MRI) is warranted to exclude secondary causes, especially at first presentation or with atypical features'],
    management:[
      'Acute attack: high-flow 100% oxygen via a non-rebreather mask and/or a subcutaneous or nasal triptan (e.g. sumatriptan SC) — oral analgesics/opioids are ineffective',
      'Arrange home oxygen for acute treatment (it is specifically effective in cluster headache)',
      'Preventive treatment during a cluster: verapamil is first-line (with ECG monitoring) — usually specialist-initiated/guided',
      'A short tapering course of corticosteroids can be used as a transitional preventive to break a cluster while verapamil takes effect',
      'Advise avoiding triggers during a bout (especially alcohol)',
      'Refer to neurology for diagnosis confirmation, imaging, and management — particularly for preventive treatment and refractory cases',
      'Provide strong reassurance and information given the extreme pain and its psychological impact (screen for low mood/suicidality)',
      'Review and optimise both acute and preventive treatment between/within clusters'],
    referral:[
      'Suspected cluster headache → neurology for diagnosis, imaging and preventive treatment',
      'First presentation or atypical features → MRI brain to exclude secondary causes',
      'Refractory or chronic cluster headache → specialist headache service',
      'Significant low mood/suicidality due to pain → mental-health support'],
    source:'NICE CKS — Headache / SIGN & BASH guidance' },

  { id:'coccydynia', title:'Tailbone (coccyx) pain', category:'Musculoskeletal', icon:'🦴',
    aka:'Coccyx pain, coccydynia',
    overview:'Pain at the coccyx (tailbone), typically worse on sitting and on rising from sitting. It is usually benign and self-limiting, commonly following a fall, childbirth or prolonged sitting. The role is conservative management plus recognising the rare sinister causes of localised bony pain.',
    features:[
      'Localised pain over the coccyx, characteristically worse when sitting (especially on hard/leaning-back surfaces) and on standing up from sitting',
      'Often follows a fall onto the buttocks, childbirth, repetitive/prolonged sitting, or occurs without clear cause',
      'Tenderness on palpation of the coccyx; pain may be reproduced by the seated position',
      'Commoner in women; obesity and rapid weight change are associated',
      'RED FLAGS (uncommon): unexplained weight loss, night pain, a mass, neurological symptoms, or a history of cancer — consider local tumour, infection or referred pathology',
      'Diagnosis is clinical; imaging is reserved for atypical/persistent cases or red flags'],
    management:[
      'Reassure: most coccydynia is self-limiting and improves over weeks to months',
      'Conservative measures: a wedge/ring ("doughnut") cushion to offload the coccyx, posture advice, avoiding prolonged sitting, and simple analgesia/NSAIDs',
      'Address constipation if it aggravates symptoms; physiotherapy (including pelvic-floor/manual therapy) can help persistent cases',
      'A local corticosteroid ± local anaesthetic injection can be considered for persistent pain',
      'Avoid routine imaging in typical presentations; arrange X-ray/MRI for atypical, persistent, or red-flag presentations',
      'Manage contributory factors (weight, sitting ergonomics)',
      'Refractory cases may need specialist pain or, rarely, surgical (coccygectomy) assessment',
      'Provide written self-care advice and review if not improving'],
    referral:[
      'Red-flag features (unexplained weight loss, night pain, a mass, neurological signs, cancer history) → urgent investigation/appropriate cancer pathway (NICE NG12)',
      'Persistent pain despite conservative measures → MSK/pain service (consider injection)',
      'Refractory, disabling coccydynia → specialist pain/surgical assessment',
      'Suspected referred pathology (e.g. rectal, gynaecological) → relevant specialty'],
    source:'NICE CKS — Coccydynia' },

  { id:'cold-sores', title:'Cold sores (herpes simplex labialis)', category:'Dermatology', icon:'💋',
    overview:'Recurrent perioral blisters caused by herpes simplex virus (usually HSV-1), which establishes latency and reactivates. They are common, self-limiting and benign in healthy people, but carry specific risks in neonates, the immunocompromised, and those with eczema (eczema herpeticum).',
    features:[
      'A prodrome of tingling/burning/itching, then a cluster of vesicles on the lip/perioral skin that crust and heal over ~7–10 days',
      'Recurrences are triggered by sunlight/UV, fever/illness, stress, fatigue, menstruation and local trauma',
      'Infectious from the prodrome until the lesions have healed; spread by direct contact (including to others and to other body sites)',
      'ECZEMA HERPETICUM: a serious widespread HSV infection in people with eczema — monomorphic "punched-out" erosions, systemic upset; a dermatological emergency',
      'Neonatal HSV (from contact around birth or with active lesions) can be severe/disseminated — a paediatric emergency',
      'Herpetic whitlow (finger) and ocular HSV (keratitis — a sight threat) are other presentations to recognise'],
    management:[
      'Most cold sores are self-limiting and need only reassurance and symptom relief (analgesia, keep the area clean)',
      'Topical antivirals (aciclovir/penciclovir) have modest benefit and work best applied at the earliest prodrome',
      'Oral antivirals (aciclovir/valaciclovir) are more useful for severe, frequent, or prolonged episodes, and for the immunocompromised — start early',
      'For frequent recurrences, consider episodic early treatment or, occasionally, suppressive antiviral therapy',
      'Advise on hygiene and avoiding transmission: don’t share utensils/towels, avoid kissing (especially neonates) and oral sex while active, and don’t touch lesions then the eyes',
      'Sun protection (lip balm with SPF) helps prevent UV-triggered recurrences',
      'Recognise and act urgently on eczema herpeticum, ocular HSV and neonatal exposure',
      'Provide written information and safety-netting on complications'],
    referral:[
      'Suspected eczema herpeticum (widespread monomorphic erosions in an eczema patient, systemic upset) → same-day dermatology/admission for IV aciclovir',
      'Suspected ocular HSV (red painful eye, dendritic ulcer, visual change) → same-day ophthalmology',
      'Cold sores/HSV exposure in a neonate or significantly immunocompromised patient → urgent specialist assessment',
      'Severe, frequent, or treatment-resistant disease → dermatology'],
    source:'NICE CKS — Herpes simplex (oral)' },

  { id:'infantile-colic', title:'Colic (infantile colic)', category:'Paediatrics', icon:'👶',
    overview:'Repeated, prolonged episodes of inconsolable crying in an otherwise healthy, thriving baby, typically in the first few months of life with no identifiable cause. It is benign and self-limiting but very distressing for parents — and the key task is excluding other causes and supporting the family.',
    features:[
      'Paroxysms of intense, inconsolable crying, often in the late afternoon/evening, in a baby who is otherwise well and feeding/growing normally',
      'The "rule of threes" describes it: crying for >3 hours/day, >3 days/week, for >3 weeks',
      'Often with drawing up of the legs, a red face, clenched fists and apparent abdominal discomfort/wind',
      'Onset usually within the first few weeks; typically resolves by 3–4 months of age',
      'RED FLAGS that point away from simple colic: fever, vomiting (especially bilious), poor feeding/weight gain, blood in stool, lethargy, a tense fontanelle, or an unwell-looking baby',
      'Consider differentials: cow’s-milk protein allergy, gastro-oesophageal reflux, infection, constipation, lactose overload, and (rarely) surgical causes'],
    management:[
      'Confirm the baby is well and thriving; perform a full examination to exclude other causes (including checking for a hernia, testicular torsion, and signs of infection)',
      'Reassure parents that colic is common, benign and self-limiting, and not their fault — supporting the family is the core intervention',
      'Practical soothing advice: holding/rocking, gentle movement, white noise, a warm bath, winding, and responding to cues',
      'Support feeding: optimise feeding technique; there is no good evidence for routinely changing formula or using simethicone/"colic drops" or lactase',
      'Consider a trial of cow’s-milk-protein exclusion (a 2-week maternal dairy-free trial if breastfeeding, or an extensively hydrolysed formula) only where allergy is suspected (e.g. associated eczema, GI or other allergic features)',
      'Acknowledge parental exhaustion and stress; advise putting the baby down safely if overwhelmed, and screen for postnatal depression',
      'Provide clear safety-netting on the red flags and where to seek help',
      'Arrange follow-up/review and signpost support (e.g. health visitor, Cry-sis)'],
    referral:[
      'Any red flag (fever, bilious/persistent vomiting, poor weight gain, blood in stool, lethargy, unwell baby) → urgent paediatric assessment',
      'Suspected cow’s-milk protein allergy not responding to dietary measures → paediatrics/dietetics',
      'Diagnostic uncertainty or faltering growth → paediatrics',
      'Parental mental-health concern (postnatal depression) or safeguarding risk → appropriate support/services'],
    source:'NICE CKS — Colic (infantile)' },

  { id:'colorectal-cancer', title:'Bowel (colorectal) cancer', category:'Gastroenterology', icon:'🎗️',
    overview:'One of the commonest cancers in the UK, usually arising from adenomatous polyps. Outcomes depend heavily on stage at diagnosis, so the primary-care priorities are promoting screening, using FIT to risk-stratify symptomatic patients, and recognising the NICE NG12 thresholds for urgent referral.',
    features:[
      'Change in bowel habit (looser stools/increased frequency), rectal bleeding, abdominal pain, weight loss and iron-deficiency anaemia',
      'Left-sided/rectal tumours: rectal bleeding, change in bowel habit, tenesmus; right-sided tumours: iron-deficiency anaemia and weight loss, often without obvious bleeding',
      'A palpable abdominal or rectal mass; bowel obstruction in advanced disease',
      'Risk factors: age, family history, adenomatous polyps, inflammatory bowel disease, obesity, smoking, alcohol, red/processed meat, and hereditary syndromes (Lynch, FAP)',
      'Prevention/early detection: the NHS Bowel Cancer Screening Programme (home FIT kit) for eligible age groups',
      'FIT (faecal immunochemical test) quantifies faecal haemoglobin and is used to triage symptomatic patients for urgent referral'],
    management:[
      'Promote uptake of the national bowel-cancer screening programme in eligible patients',
      'Use FIT to guide urgent referral in symptomatic patients (a faecal haemoglobin ≥10 µg Hb/g supports a suspected-cancer referral), while not letting a negative FIT override strong clinical concern',
      'Recognise and act on the NICE NG12 referral thresholds (below) — do not delay',
      'Check FBC for iron-deficiency anaemia and examine the abdomen/rectum',
      'Refer confirmed cancers to the colorectal MDT; support patients through staging (CT, MRI rectum) and treatment decisions',
      'Identify possible hereditary cancer (young onset, strong family history, multiple primaries) and refer for genetics/Lynch testing',
      'Support lifestyle risk reduction: stop smoking, reduce alcohol and processed meat, maintain a healthy weight and be active',
      'Provide information, manage symptoms, and coordinate surveillance/follow-up after treatment'],
    referral:[
      'NICE NG12 2WW colorectal pathway: refer adults with an abdominal/rectal mass; aged ≥40 with abdominal pain + unexplained weight loss; aged ≥50 with unexplained rectal bleeding; aged ≥60 with iron-deficiency anaemia or a change in bowel habit; and use FIT (≥10 µg Hb/g) to support urgent referral in other symptomatic adults',
      'Suspected bowel obstruction or significant GI bleeding → emergency admission',
      'Positive screening FIT → colonoscopy via the screening programme',
      'Suspected Lynch syndrome/FAP → clinical genetics'],
    source:'NICE NG12 / NICE DG56 (FIT) / NHS Bowel Cancer Screening' },

  { id:'breast-cancer', title:'Breast cancer', category:'Women’s health', icon:'🎗️',
    overview:'The commonest cancer in women in the UK (and a rare but real diagnosis in men). Early detection through screening and prompt referral of symptomatic patients markedly improves outcomes. The primary-care role is examination, recognising the NICE NG12 referral criteria, and supporting risk assessment for those with a family history.',
    features:[
      'A new discrete breast lump or thickening (the commonest presentation), particularly if hard, irregular, fixed or painless',
      'Skin changes: dimpling/puckering, peau d’orange, nipple inversion (new), or eczema-like change of the nipple/areola (Paget’s disease of the breast)',
      'Nipple discharge — concerning if unilateral, single-duct, bloodstained or spontaneous',
      'Axillary lump/lymphadenopathy; in advanced disease, fixation, ulceration or systemic features',
      'Risk factors: age, female sex, family history/BRCA, early menarche/late menopause, nulliparity, HRT, obesity and alcohol',
      'Prevention/detection: the NHS Breast Screening Programme (mammography) for eligible women; men present with a retroareolar lump'],
    management:[
      'Examine both breasts and axillae; assess any lump’s characteristics and associated skin/nipple changes',
      'Refer all suspicious findings on the suspected-cancer pathway promptly — do not "watch and wait" a discrete lump',
      'Encourage uptake of breast screening and promote breast awareness (report any new change)',
      'Assess family history; refer those meeting criteria for familial breast cancer to genetics/family-history clinics (possible BRCA testing, enhanced surveillance, risk-reducing options)',
      'Support lifestyle risk reduction: healthy weight, reduce alcohol, and discuss HRT risks/benefits individually',
      'For confirmed cancer, coordinate with the breast MDT and support the patient through diagnosis and treatment',
      'Manage treatment-related issues in primary care (e.g. menopausal symptoms on endocrine therapy, bone health, lymphoedema) and survivorship',
      'Provide information and psychological support throughout'],
    referral:[
      'NICE NG12 2WW breast pathway: refer people aged ≥30 with an unexplained breast lump (± pain); aged ≥50 with unilateral nipple changes (discharge, retraction, other concern); skin changes suggestive of breast cancer; and consider for an axillary lump',
      'Aged <30 with an unexplained breast lump → non-urgent referral (consider 2WW if other concerning features)',
      'Strong family history meeting criteria → familial breast-cancer/genetics service',
      'Confirmed cancer → breast MDT'],
    source:'NICE NG12 / NICE CG164 (familial breast cancer)' },

  { id:'colour-blindness', title:'Colour vision deficiency (colour blindness)', category:'Ophthalmology', icon:'👁️',
    overview:'Reduced ability to distinguish certain colours, usually an inherited (X-linked) red-green deficiency affecting around 1 in 12 men. It is generally a lifelong, non-progressive variation rather than a disease, but acquired colour deficiency can signal eye or systemic disease, and there are practical/occupational implications.',
    features:[
      'Inherited red-green deficiency is by far the commonest — present from birth, stable, and affecting many more men than women (X-linked)',
      'Difficulty distinguishing reds/greens (and sometimes blues/yellows in rarer types); often noticed at school or with specific tasks',
      'Usually no other visual symptoms — acuity and the eye examination are otherwise normal in inherited forms',
      'ACQUIRED colour deficiency (new, progressive, asymmetric, or with other visual symptoms) may indicate optic nerve disease, macular disease, or drug toxicity (e.g. ethambutol, hydroxychloroquine, digoxin)',
      'Practical implications: certain occupations require normal colour vision (e.g. pilots, train drivers, some electrical/armed-forces roles)',
      'Diagnosis: Ishihara plates (screening) and more detailed tests (e.g. anomaloscope) via optometry'],
    management:[
      'Confirm via optometric colour-vision testing; distinguish stable inherited deficiency from new/acquired change',
      'Reassure for inherited deficiency — it is a lifelong variation, not an illness, and usually requires no treatment',
      'Provide practical support: strategies for daily tasks, awareness at school, and information on colour-confident tools/apps; colour-correcting lenses help some people partially',
      'Advise on occupational implications and signpost careers guidance where relevant',
      'Investigate acquired/progressive colour deficiency for an underlying cause — refer to ophthalmology, and review potentially toxic medications',
      'For children, inform the school so teaching/materials can be adapted',
      'Offer genetic information for inherited deficiency (inheritance pattern and family implications)',
      'Document the deficiency clearly in the record'],
    referral:[
      'Acquired, progressive, asymmetric colour deficiency or associated visual symptoms → ophthalmology (exclude optic nerve/macular disease)',
      'Suspected drug-induced colour change (e.g. ethambutol, hydroxychloroquine) → review/monitor per protocol and refer as needed',
      'Occupational assessment requirements → relevant occupational/optometry service',
      'Diagnostic uncertainty → optometry/ophthalmology'],
    source:'NICE CKS / optometry guidance' },

  { id:'common-cold', title:'Common cold', category:'Respiratory', icon:'🤧',
    overview:'A self-limiting viral upper-respiratory-tract infection — the commonest acute illness seen in practice. The clinical value lies in confident reassurance, sensible self-care advice, antibiotic stewardship, and recognising the minority who have, or develop, something more serious.',
    features:[
      'Gradual onset of nasal congestion/discharge, sneezing, sore throat, cough and mild malaise; fever is usually mild (higher in children)',
      'Caused by many viruses (rhinovirus most often); spread by droplets and contact',
      'Self-limiting — symptoms peak at 2–3 days and usually resolve within 1–2 weeks, though cough can linger up to 3 weeks',
      'Green/discoloured nasal mucus is normal in a cold and does not indicate a bacterial infection or need for antibiotics',
      'Complications to watch for: secondary bacterial sinusitis/otitis media, lower-respiratory infection, and exacerbations of asthma/COPD',
      'Differentials/overlap: influenza (more abrupt, systemic), COVID-19, allergic rhinitis, and streptococcal sore throat'],
    management:[
      'Reassure that it is a self-limiting viral illness and explain the expected course and duration',
      'Self-care: rest, fluids, paracetamol/ibuprofen for fever/aches, and symptomatic measures (saline nasal drops, steam, honey/lozenges for cough/throat)',
      'Do not prescribe antibiotics for an uncomplicated cold — they do not help and cause harm/resistance',
      'Decongestants and over-the-counter remedies give modest, short-term relief; avoid decongestants in young children and use cautiously',
      'Give clear safety-netting: seek review for high/persistent fever, breathing difficulty, symptoms worsening after initial improvement, or illness lasting beyond the expected time',
      'Advise hygiene measures (handwashing, catching coughs/sneezes) to reduce spread',
      'Have a lower threshold for review/assessment in infants, the frail, and those with chronic respiratory disease',
      'Address specific complications (sinusitis, otitis media, lower-respiratory infection) on their own merits if they develop'],
    referral:[
      'Signs of serious illness (severe/worsening breathlessness, hypoxia, sepsis, marked systemic compromise) → urgent assessment/admission',
      'Complications such as significant bacterial sinusitis, otitis media, or lower-respiratory infection → manage/refer as appropriate',
      'Exacerbation of underlying asthma/COPD → manage per exacerbation pathway',
      'Diagnostic uncertainty or unusually prolonged illness → reassess'],
    source:'NICE CKS — Common cold' },

  { id:'compartment-syndrome', title:'Compartment syndrome', category:'Musculoskeletal', icon:'🦵',
    overview:'Raised pressure within a closed fascial compartment that compromises tissue perfusion. ACUTE compartment syndrome is a surgical emergency — usually after a fracture or crush injury — that causes irreversible muscle and nerve damage within hours if not decompressed. Chronic exertional compartment syndrome is a separate, non-urgent entity.',
    features:[
      'ACUTE: pain out of proportion to the injury and worsening despite analgesia is the cardinal early symptom',
      'Pain on passive stretch of the muscles in the affected compartment is an early, sensitive sign',
      'The classic "6 Ps" (pain, paraesthesia, pallor, paralysis, pulselessness, perishingly cold) are LATE — pulselessness and paralysis indicate established, often irreversible, damage',
      'Common settings: tibial/forearm fractures, crush injuries, tight casts/bandages, reperfusion, and burns',
      'A tense, swollen compartment on palpation; diagnosis is clinical (and by compartment-pressure measurement where available)',
      'CHRONIC exertional compartment syndrome: recurrent exercise-induced limb pain/tightness that resolves with rest — not an emergency'],
    management:[
      'For suspected acute compartment syndrome, act immediately — this is time-critical and limb/life-threatening',
      'Remove or split any constricting casts/dressings down to skin and keep the limb at heart level (do not elevate above the heart, which reduces perfusion)',
      'Give analgesia and oxygen, but do not let pain relief mask deterioration; do not delay for investigations',
      'Refer as an emergency to orthopaedics/surgery — definitive treatment is urgent fasciotomy to decompress the compartment',
      'Monitor neurovascular status while arranging immediate transfer',
      'For chronic exertional compartment syndrome: activity modification and physiotherapy first; refer for diagnosis (exercise compartment-pressure testing) and consider elective fasciotomy if persistent',
      'Have a high index of suspicion after fractures and crush injuries — escalating pain is the key warning',
      'Document neurovascular findings and the timeline carefully'],
    referral:[
      'Suspected acute compartment syndrome → immediate emergency orthopaedic/surgical referral for fasciotomy — do not delay',
      'Crush injury, tight cast with escalating pain, or post-fracture deterioration → urgent assessment',
      'Suspected chronic exertional compartment syndrome → elective orthopaedics/sports medicine for testing',
      'Established neurovascular deficit → emergency'],
    source:'NICE CKS / BOAST (orthopaedic) guidance' },

  { id:'congenital-heart-disease', title:'Congenital heart disease', category:'Cardiovascular & Renal', icon:'🫀',
    overview:'Structural heart abnormalities present from birth — the commonest group of congenital anomalies. They range from small defects that close spontaneously to complex, life-threatening lesions. With modern care most children survive to adulthood, creating a growing population of adults with congenital heart disease (ACHD) needing lifelong specialist follow-up.',
    features:[
      'Acyanotic (left-to-right shunts/obstructions): ventricular and atrial septal defects, patent ductus arteriosus, coarctation, aortic/pulmonary stenosis — may present with a murmur, heart failure, or poor feeding/faltering growth',
      'Cyanotic lesions (e.g. tetralogy of Fallot, transposition): central cyanosis, often presenting in the neonatal period',
      'Antenatal detection (fetal anomaly scan) and the newborn examination (including pulse oximetry screening) identify many cases',
      'Presenting clues in infants: a murmur, cyanosis, tachypnoea, sweating/difficulty with feeds, faltering growth, and recurrent chest infections',
      'Associations: Down’s syndrome, 22q11 deletion (DiGeorge), Turner syndrome, and maternal factors (rubella, diabetes, alcohol)',
      'Adults with CHD may present with arrhythmia, heart failure, or complications of previous repairs'],
    management:[
      'Detect early: thorough newborn and infant examination (femoral pulses, murmurs, cyanosis, saturations) and prompt assessment of concerning findings',
      'Refer suspected congenital heart disease to paediatric cardiology for echocardiography and diagnosis',
      'Management is specialist and lesion-specific: observation for small defects (many close), catheter or surgical intervention for significant lesions',
      'A collapsed/cyanosed neonate may have a duct-dependent lesion — this is an emergency (prostaglandin infusion is used to keep the duct open while transferring)',
      'Support growth and feeding, immunisations (including extra protection where advised), and treat intercurrent illness promptly',
      'Ensure lifelong follow-up: arrange/maintain transition to adult congenital heart disease (ACHD) services',
      'Advise on endocarditis risk and prevention where relevant, and pre-pregnancy counselling for women with CHD',
      'Support families with information and coordinate multidisciplinary care'],
    referral:[
      'Collapsed/cyanosed neonate or suspected duct-dependent lesion → emergency neonatal/paediatric admission',
      'Suspected congenital heart disease (murmur with symptoms, cyanosis, faltering growth, abnormal saturations) → paediatric cardiology',
      'Adults with congenital heart disease → specialist ACHD service for lifelong follow-up',
      'Pregnancy in a woman with CHD → specialist cardiac-obstetric care'],
    source:'NICE CKS / paediatric & ACHD cardiology guidance' },

  { id:'ddh', title:'Congenital hip dislocation (developmental dysplasia of the hip)', category:'Paediatrics', icon:'👶',
    overview:'A spectrum of abnormal hip development — from a shallow (dysplastic) socket to frank dislocation — present at or developing after birth. Early detection through newborn screening allows simple, effective treatment; late diagnosis risks the need for surgery and long-term hip problems, so vigilance at every infant check matters.',
    features:[
      'Often asymptomatic in the newborn — detection relies on screening examination (Barlow and Ortolani manoeuvres) at birth and the 6–8-week check',
      'Clinical signs in infants: hip instability/"clunk", asymmetry of skin/thigh creases, limited or asymmetric hip abduction, and apparent limb-length discrepancy (Galeazzi sign)',
      'Later signs (if missed): a limp, toe-walking, or waddling gait once walking begins',
      'RISK FACTORS (warrant screening ultrasound): breech presentation (at/after 36 weeks or at birth), a family history of DDH, and (per local policy) other factors — these prompt ultrasound regardless of a normal exam',
      'Commoner in girls, first-borns, and breech babies; the left hip is most often affected',
      'Diagnosis: ultrasound under ~4.5 months (before ossification), then X-ray in older infants'],
    management:[
      'Examine the hips at the newborn and 6–8-week checks (Barlow/Ortolani, abduction, creases, leg length)',
      'Arrange selective ultrasound screening for risk factors (breech, family history) even if the examination is normal',
      'Refer abnormal/uncertain examinations promptly to paediatric orthopaedics for assessment',
      'Early treatment (under ~6 months) is usually a Pavlik harness to hold the hip reduced while it develops — simple and effective',
      'Later or failed-harness cases may need closed/open reduction and a hip spica, or surgery',
      'The earlier the diagnosis, the simpler the treatment and the better the outcome — emphasise timely referral',
      'Provide parental information and support; arrange orthopaedic follow-up to confirm normal development',
      'Maintain a low threshold for re-examination/referral if a limp or abnormal gait develops later'],
    referral:[
      'Abnormal or unstable hip examination (positive Barlow/Ortolani, limited abduction, asymmetry) → paediatric orthopaedics',
      'Risk factors (breech, family history) → selective hip ultrasound per protocol',
      'Late presentation (limp, abnormal gait, leg-length discrepancy) → urgent orthopaedic assessment',
      'Confirmed DDH → paediatric orthopaedics for treatment and follow-up'],
    source:'NICE CKS / NIPE screening / BSCOS guidance' },

  { id:'contact-dermatitis', title:'Contact dermatitis', category:'Dermatology', icon:'🧴',
    overview:'Inflammation of the skin from external agents — either irritant (direct damage, dose-dependent, the commoner type) or allergic (a delayed type-IV hypersensitivity to a specific allergen). Identifying and avoiding the cause is the cornerstone; it is a common occupational disease, especially of the hands.',
    features:[
      'Itchy, red, scaly, sometimes vesicular or fissured skin; chronic disease becomes thickened (lichenified)',
      'Irritant contact dermatitis: from repeated exposure to water, soaps/detergents, solvents, friction — common on the hands (e.g. healthcare, hairdressing, cleaning, catering)',
      'Allergic contact dermatitis: a delayed reaction to a specific allergen (e.g. nickel, fragrances, preservatives, rubber/latex, hair dye/PPD, topical antibiotics) — pattern often matches the contact area',
      'Distribution is a clue: hands (occupational/wet work), face/eyelids (cosmetics, airborne), earlobes/wrist (nickel jewellery), feet (footwear)',
      'Occupational relevance: improvement away from work (weekends/holidays) and flares on return',
      'Diagnosis is clinical from history/pattern; patch testing identifies allergic contact allergens'],
    management:[
      'Identify and avoid the cause: a careful history of exposures, occupation, hobbies and products is essential',
      'Skin protection: reduce wet work, use gloves appropriately, frequent emollients, and avoid soaps (use soap substitutes)',
      'Treat the inflammation with topical corticosteroids of appropriate potency (e.g. potent for hands/lichenified skin), tapering as it settles',
      'Manage secondary infection if present, and treat fissures',
      'For suspected allergic contact dermatitis, refer for patch testing to identify the allergen, then advise on strict avoidance (including reading product ingredient lists)',
      'Address occupational causes: workplace measures, protective equipment, and report as occupational dermatitis where relevant',
      'Provide written hand-care/skin-protection advice and review',
      'Consider differentials (atopic eczema, psoriasis, fungal infection) where the diagnosis is unclear'],
    referral:[
      'Suspected allergic contact dermatitis or persistent/unexplained dermatitis → dermatology for patch testing',
      'Severe, widespread, or treatment-resistant disease → dermatology',
      'Occupational dermatitis affecting work → dermatology/occupational health (and report as appropriate)',
      'Diagnostic uncertainty → dermatology'],
    source:'NICE CKS — Dermatitis (contact)' },

  { id:'corns-calluses', title:'Corns and calluses', category:'Dermatology', icon:'🦶',
    overview:'Areas of thickened skin (hyperkeratosis) caused by repeated pressure or friction — calluses are diffuse, corns are focal with a central core. They are common and benign, but in people with diabetes or neuropathy they can overlie or precipitate ulceration, so footcare and risk assessment matter.',
    features:[
      'Callus: a broad area of thickened, hardened skin, usually on the sole/weight-bearing areas, generally painless',
      'Corn: a smaller, well-defined area of thickening with a central keratin core, often over bony prominences/toes, and frequently painful (a "wearing a stone" sensation)',
      'Caused by repeated mechanical pressure/friction: ill-fitting footwear, foot deformity (bunions, hammer toes), high activity, and abnormal gait/weight-bearing',
      'Differential: verruca (plantar wart — interrupts skin lines, painful on lateral squeeze, may have black dots), and (rarely) other lesions',
      'In diabetes/neuropathy/peripheral arterial disease, a callus can mask or overlie an ulcer — a key risk',
      'Diagnosis is clinical'],
    management:[
      'Address the cause: well-fitting, cushioned footwear with a roomy toe box, and offloading with pads/orthoses for pressure points and foot deformity',
      'Reduce the thickened skin: regular use of a pumice stone/foot file after soaking, and emollients to soften the skin',
      'Podiatry for paring/debridement of painful corns/calluses and for orthotics and footwear advice',
      'Avoid corn plasters containing salicylic acid in people with diabetes, neuropathy, or poor circulation (risk of ulceration)',
      'Treat any associated foot deformity contributing to pressure',
      'In high-risk feet (diabetes, neuropathy, PAD), refer to podiatry and arrange foot-risk assessment; never ignore a callus that overlies redness, breakdown, or discharge',
      'Distinguish from verrucae (treated differently)',
      'Provide footcare advice and review high-risk patients regularly'],
    referral:[
      'Diabetic/neuropathic/ischaemic foot, or a callus overlying ulceration/infection → podiatry / diabetic foot service (urgently if ulcer/infection)',
      'Painful, recurrent, or large corns/calluses → podiatry',
      'Underlying foot deformity needing correction → orthopaedics/podiatric surgery',
      'Diagnostic uncertainty → assessment'],
    source:'NICE CKS — Corns and calluses' },

  { id:'cradle-cap', title:'Cradle cap (infantile seborrhoeic dermatitis)', category:'Paediatrics', icon:'👶',
    overview:'A very common, benign, self-limiting scalp condition of young infants — greasy yellow scales and crusts on the scalp, sometimes spreading to the face and flexures. It is harmless, not itchy, and not due to poor hygiene; reassurance and simple measures are all that is usually needed.',
    features:[
      'Greasy, yellow-brown scales and crusts on the scalp ("cradle cap"), sometimes with mild redness',
      'May extend to the eyebrows, behind the ears, the face and the nappy/flexural areas (infantile seborrhoeic dermatitis)',
      'Typically appears in the first weeks–months of life and usually resolves by around 6–12 months',
      'The baby is otherwise well and the rash is not itchy or distressing to the infant (a key contrast with atopic eczema, which is itchy)',
      'Differential: atopic eczema (itchy, often spares the nappy area, flexural), tinea capitis, and psoriasis',
      'Diagnosis is clinical; secondary infection is uncommon'],
    management:[
      'Reassure: cradle cap is benign, self-limiting, and not caused by poor hygiene or allergy',
      'Simple measures: regular washing of the scalp with a baby shampoo and gentle brushing to loosen scales',
      'Soften and loosen thick scales with an emollient or natural oil (e.g. baby/olive/coconut oil) applied for a while, then gently brushed and washed out',
      'For persistent/troublesome cases, a topical antifungal or mild anti-seborrhoeic shampoo/cream can be used',
      'Avoid picking the scales or using harsh/irritant products',
      'Treat any secondary infection if it develops (uncommon)',
      'Reassess if the rash is itchy, weeping, widespread, or the baby is unwell (reconsider eczema/infection)',
      'Provide written information and reassurance about the natural course'],
    referral:[
      'Diagnostic uncertainty (e.g. possible tinea capitis, psoriasis, or troublesome atopic eczema) → assessment/dermatology',
      'Severe, widespread, or treatment-resistant disease → dermatology',
      'Secondary infection not responding → review/treat',
      'Associated failure to thrive or systemic features → paediatrics (consider rarer causes)'],
    source:'NICE CKS — Seborrhoeic dermatitis (infantile)' },

  { id:'craniosynostosis', title:'Craniosynostosis', category:'Paediatrics', icon:'👶',
    overview:'Premature fusion of one or more cranial sutures, restricting skull growth perpendicular to the fused suture and producing a characteristic abnormal head shape. It must be distinguished from benign positional plagiocephaly. Significant or syndromic cases risk raised intracranial pressure and need specialist craniofacial care.',
    features:[
      'An abnormal head shape determined by which suture has fused — e.g. sagittal synostosis gives a long, narrow head (scaphocephaly); coronal/metopic synostosis gives other characteristic shapes',
      'A palpable bony ridge over the fused suture and an abnormal shape that does not correct with repositioning (unlike positional plagiocephaly)',
      'A small or prematurely closed anterior fontanelle and restricted skull growth',
      'Raised intracranial pressure (especially with multiple sutures/syndromic forms): irritability, vomiting, developmental concerns, bulging fontanelle, and (later) papilloedema',
      'Syndromic associations (e.g. Apert, Crouzon, Pfeiffer) have additional facial/limb features and a higher complication risk',
      'Distinguish clearly from positional plagiocephaly (no suture ridge; head shape improves with repositioning)'],
    management:[
      'Examine the sutures, fontanelle and head shape; distinguish craniosynostosis from benign positional deformity',
      'Refer suspected craniosynostosis to a paediatric/craniofacial service for assessment (clinical ± CT imaging)',
      'Confirmed cases are managed by specialist craniofacial MDTs; surgery (cranial vault remodelling or endoscopic strip craniectomy) may be needed to allow brain growth, relieve/prevent raised ICP, and improve shape',
      'Monitor for raised intracranial pressure and developmental progress',
      'Assess for syndromic features and arrange genetics input where indicated',
      'Support the family with information and coordinate multidisciplinary follow-up',
      'Do not mistake or delay genuine synostosis as "flat head" — and equally, reassure clearly when it is positional',
      'Arrange timely specialist review, as the timing of surgery matters'],
    referral:[
      'Suspected craniosynostosis (suture ridge, abnormal/worsening head shape, restricted growth) → paediatric/craniofacial service',
      'Features of raised intracranial pressure → urgent assessment',
      'Suspected syndromic craniosynostosis → craniofacial MDT + genetics',
      'Diagnostic uncertainty vs positional plagiocephaly → paediatric assessment'],
    source:'NICE CKS / craniofacial specialist guidance' },

  { id:'croup', title:'Croup (laryngotracheobronchitis)', category:'Paediatrics', icon:'👶',
    overview:'A common viral upper-airway infection of young children (usually 6 months–3 years), typically parainfluenza, causing subglottic inflammation. The hallmark is a barking cough with stridor. Most is mild and steroid-responsive; the key is assessing severity and distinguishing it from rarer, dangerous airway emergencies.',
    features:[
      'A barking ("seal-like") cough, hoarse voice, and inspiratory stridor, often preceded by coryza and worse at night',
      'Symptoms typically fluctuate, worsening with distress/crying; low-grade fever is common',
      'Severity assessment: stridor at rest, chest-wall recession, agitation/lethargy, and signs of hypoxia indicate more severe disease',
      'Mild croup: barking cough with little/no stridor at rest and no recession; the child is well between coughing bouts',
      'RED FLAGS / alternative diagnoses: drooling and a toxic, still child (epiglottitis), sudden onset while eating/playing (inhaled foreign body), or a harsh persistent stridor (bacterial tracheitis) — examine the throat only with great caution',
      'Diagnosis is clinical; avoid distressing investigations/throat examination in a child with respiratory distress'],
    management:[
      'Assess severity and keep the child calm (distress worsens airway obstruction) — let them sit with a parent',
      'Give a single dose of oral corticosteroid (dexamethasone, or prednisolone) to ALL children with croup, including mild cases — it reduces severity and reattendance',
      'Mild croup: manage at home with the steroid dose, antipyretics/fluids, and clear safety-netting advice',
      'Moderate/severe croup: refer to hospital; nebulised adrenaline gives rapid temporary relief in severe cases, with oxygen and close monitoring',
      'Do not examine the throat or upset the child if epiglottitis is a possibility — keep the airway undisturbed and get senior/anaesthetic help',
      'Safety-net: seek urgent help for stridor at rest, increasing respiratory effort/recession, drooling, pallor/cyanosis, drowsiness, or a struggling-to-breathe child',
      'Advise on the usually short, self-limiting course (a few days) with the cough settling',
      'Reassess or admit if there is diagnostic doubt, a young infant, or significant comorbidity'],
    referral:[
      'Moderate–severe croup (stridor at rest, significant recession, agitation/lethargy, hypoxia) → emergency hospital admission',
      'Suspected epiglottitis (toxic, drooling, sitting forward, soft stridor) or bacterial tracheitis → 999 / emergency airway management; do not examine the throat',
      'Suspected inhaled foreign body → urgent assessment',
      'Young infant, recurrent/atypical croup, or significant comorbidity → paediatric assessment'],
    source:'NICE CKS — Croup' },

  { id:'cystic-fibrosis', title:'Cystic fibrosis', category:'Respiratory', icon:'🫁',
    overview:'An autosomal-recessive multisystem disease caused by CFTR gene mutations, producing thick secretions that damage the lungs, pancreas and other organs. Most UK cases are detected by newborn screening. Care is highly specialised; life expectancy has risen markedly, including with new CFTR-modulator drugs.',
    features:[
      'Respiratory: chronic productive cough, recurrent chest infections, bronchiectasis, and progressive obstructive lung disease with chronic Pseudomonas colonisation',
      'Pancreatic exocrine insufficiency: steatorrhoea, malabsorption and faltering growth; CF-related diabetes develops over time',
      'GI: meconium ileus in neonates, distal intestinal obstruction syndrome, and CF-related liver disease',
      'Other: male infertility (absent vas deferens), nasal polyps/sinusitis, osteoporosis, and salt loss',
      'Most diagnosed via newborn bloodspot screening; sweat test (raised chloride) and genetic testing confirm',
      'Late/atypical presentations can occur with milder mutations'],
    management:[
      'Care is led by a specialist CF multidisciplinary centre — the GP supports shared care, acute issues and coordination',
      'Airway clearance physiotherapy, mucolytics (e.g. dornase alfa, hypertonic saline), and prompt, often prolonged, antibiotics for infections/exacerbations',
      'CFTR modulators (e.g. elexacaftor-tezacaftor-ivacaftor) have transformed outcomes for eligible genotypes',
      'Pancreatic enzyme replacement (PERT) with all meals/snacks, fat-soluble vitamin supplementation, and a high-energy diet with dietitian support',
      'Screen for and manage CF-related diabetes, liver disease, bone health and fertility issues',
      'Vaccinations (including influenza), avoid cross-infection (segregation), and treat exacerbations early',
      'Provide psychological support and coordinate transition to adult CF services',
      'In primary care, recognise and refer exacerbations promptly and support adherence to a heavy treatment burden'],
    referral:[
      'Suspected CF (positive newborn screen, suggestive symptoms, faltering growth with respiratory/GI features) → specialist CF centre for diagnosis',
      'Exacerbations or new respiratory deterioration → CF centre (often need IV antibiotics)',
      'Complications (CF-related diabetes, liver disease, DIOS, haemoptysis) → relevant specialist/CF team',
      'All confirmed cases → lifelong specialist CF MDT follow-up'],
    source:'NICE NG78 (Cystic fibrosis)' },

  { id:'cystitis', title:'Cystitis (lower urinary tract infection)', category:'Urology', icon:'💧',
    overview:'Inflammation of the bladder, usually from a bacterial lower urinary tract infection. It is common in women and mostly uncomplicated and self-limiting or quickly treated. The skill is treating uncomplicated cases simply, recognising complicated/upper-tract infection, and avoiding over-treatment of asymptomatic bacteriuria.',
    features:[
      'Dysuria, urinary frequency and urgency, suprapubic discomfort, and cloudy/offensive urine; sometimes visible haematuria',
      'In uncomplicated cystitis the patient is systemically well, without fever, loin pain or rigors',
      'PYELONEPHRITIS (upper UTI): fever, loin pain/tenderness, rigors and systemic illness — needs different, more aggressive management',
      '"Complicated" or higher-risk groups: men, pregnant women, children, catheterised patients, the immunocompromised, and those with structural/renal abnormalities',
      'Asymptomatic bacteriuria (a positive culture without symptoms) should generally NOT be treated — except in pregnancy',
      'Diagnosis: clinical ± dipstick (use with care; less reliable in older adults) and culture in pregnancy, men, children, recurrent/complicated cases, or treatment failure'],
    management:[
      'Uncomplicated cystitis in non-pregnant women: a short course of first-line antibiotics (e.g. nitrofurantoin, or trimethoprim per local resistance) — many mild cases can also be managed with self-care/back-up prescriptions',
      'Advise on self-care (fluids, analgesia) and safety-netting for systemic symptoms',
      'Send a urine culture in pregnancy, men, children, recurrent/complicated infection, catheter-associated infection, or treatment failure',
      'Treat pyelonephritis promptly with appropriate antibiotics and assess for admission if systemically unwell/pregnant',
      'In pregnancy, treat symptomatic UTI and asymptomatic bacteriuria with a pregnancy-safe antibiotic and arrange test of cure',
      'In men, treat as a complicated/possible prostatic infection (longer course, consider prostatitis) and consider underlying causes',
      'Investigate recurrent UTIs (≥2 in 6 months/≥3 in a year): post-void residual, consider causes, advise self-care, and consider prophylaxis or topical oestrogen in postmenopausal women',
      'Investigate visible haematuria and persistent/unexplained urinary symptoms appropriately'],
    referral:[
      'Pyelonephritis/severe or systemic illness, or UTI in pregnancy that is systemically unwell → assess for admission',
      'Visible haematuria, or non-visible haematuria with risk factors, or recurrent UTI with red flags → urology (consider NICE NG12 bladder/renal cancer pathway, especially age ≥45 with visible haematuria)',
      'Recurrent/complicated UTI, men with recurrent UTI, or structural concern → urology',
      'Children with UTI → assess/refer per NICE paediatric UTI guidance'],
    source:'NICE NG109 (UTI — lower) / NICE CKS' },

  { id:'cyclothymia', title:'Cyclothymia', category:'Mental health', icon:'🧠',
    overview:'A chronic mood disorder of fluctuating subthreshold highs (hypomanic-like) and lows (depressive) that never meet the full criteria for a hypomanic or major depressive episode. It is persistent (≥2 years), often unrecognised, and carries a risk of progression to bipolar disorder.',
    features:[
      'Persistent (≥2 years; ≥1 year in young people) instability of mood with numerous periods of mild elevation and mild depression',
      'Symptoms do not reach the threshold for a full hypomanic or major depressive episode, and the person is rarely euthymic for long',
      'Functional impact through unpredictable mood, irritability, and disrupted relationships and work',
      'Frequently misattributed to "personality" or missed; often a long history before recognition',
      'Increased risk of evolving into bipolar I or II disorder; high comorbidity with anxiety and substance misuse',
      'Differential: bipolar I/II (full episodes), borderline personality disorder (reactive, interpersonal instability), and recurrent depression'],
    management:[
      'Take a careful longitudinal mood history (including any clear hypomanic/depressive episodes) to distinguish from bipolar disorder',
      'Refer to mental-health services for diagnosis and a management plan — cyclothymia sits on the bipolar spectrum and warrants specialist assessment',
      'Psychoeducation about the condition, mood monitoring/charting, and lifestyle stability (regular sleep, routine, reducing alcohol/substances)',
      'Psychological therapy (e.g. CBT) can help mood regulation and relapse prevention',
      'Be cautious with antidepressants alone — they can destabilise mood/precipitate hypomania; prescribe within a specialist-guided plan',
      'Mood stabilisers may be used under specialist direction for significant impairment or evolving bipolarity',
      'Treat comorbid anxiety and substance misuse',
      'Monitor for progression to bipolar disorder and provide ongoing review and support'],
    referral:[
      'Suspected cyclothymia / bipolar-spectrum disorder → mental-health services for diagnosis and management',
      'Emergence of clear hypomanic/manic or major depressive episodes → specialist review (reconsider bipolar diagnosis)',
      'Significant risk, comorbidity, or functional impairment → community mental-health team',
      'Young people with mood instability → CAMHS'],
    source:'NICE CG185 (Bipolar disorder) / NICE CKS' }

  );
})();
